use anyhow::{Context, Result};
use std::collections::BTreeMap;
use tree_sitter::{Node, Parser};

use crate::cfg::{CfgNodeKind, ControlFlowGraph, FunctionParam, ResourceKind};
use crate::extractors::ir::{
    build_declaration_props as ir_build_declaration_props,
    build_entry_props as ir_build_entry_props,
    build_expression_statement_props as ir_build_expression_statement_props,
    build_return_props as ir_build_return_props, ir_as_simple_ident, ir_call_callee_args,
};
use crate::extractors::LanguageExtractor;
use crate::source_map::SourceSpan;

pub struct PythonExtractor;

impl LanguageExtractor for PythonExtractor {
    fn language_id(&self) -> &str {
        "python"
    }

    fn file_extensions(&self) -> &[&str] {
        &[".py", ".pyw"]
    }

    fn extract(&self, source: &str, file_path: &str) -> Result<Vec<ControlFlowGraph>> {
        let mut parser = Parser::new();
        let language = tree_sitter_python::LANGUAGE.into();
        parser
            .set_language(&language)
            .context("failed to set Python grammar")?;

        let tree = parser
            .parse(source, None)
            .context("failed to parse Python source")?;

        let root = tree.root_node();
        let mut cfgs = Vec::new();

        extract_python_functions(&root, source, file_path, &mut cfgs)?;

        Ok(cfgs)
    }
}

fn extract_python_functions(
    node: &Node,
    source: &str,
    file_path: &str,
    cfgs: &mut Vec<ControlFlowGraph>,
) -> Result<()> {
    // Collect module-level bindings once at the file root and thread the
    // resulting JSON-encoded preamble into every function's Entry node so
    // gnexec can hoist them into scope before walking the body.
    let preamble = if node.kind() == "module" {
        collect_python_preamble(node, source)
    } else {
        None
    };
    extract_python_functions_with_preamble(node, source, file_path, cfgs, preamble.as_deref())
}

fn extract_python_functions_with_preamble(
    node: &Node,
    source: &str,
    file_path: &str,
    cfgs: &mut Vec<ControlFlowGraph>,
    module_preamble: Option<&str>,
) -> Result<()> {
    if node.kind() == "function_definition" {
        let name = node
            .child_by_field_name("name")
            .map(|n| node_text(n, source))
            .unwrap_or_else(|| "anonymous".to_string());

        let cfg = extract_python_function_cfg(node, source, file_path, &name, module_preamble)?;
        cfgs.push(cfg);
    }

    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            extract_python_functions_with_preamble(
                &child,
                source,
                file_path,
                cfgs,
                module_preamble,
            )?;
        }
    }

    Ok(())
}

/// Walk Python module-level statements and emit a JSON-encoded array of
/// `{bind, expr}` declarations for each top-level `X = expr`. Skips imports
/// (handled by `multi_file.rs`) and conditional / function-local bindings
/// (only direct children of `module`). Returns None if there are no
/// hoistable bindings — the Entry property is then omitted entirely.
fn collect_python_preamble(module_node: &Node, source: &str) -> Option<String> {
    let mut decls: Vec<serde_json::Value> = Vec::new();
    let mut cursor = module_node.walk();
    for child in module_node.named_children(&mut cursor) {
        if child.kind() != "expression_statement" {
            continue;
        }
        // expression_statement wraps a single child; for `X = expr` that's
        // an `assignment` with `left` (target) and `right` (value).
        let inner = child.named_child(0)?;
        if inner.kind() != "assignment" {
            continue;
        }
        let lhs = inner.child_by_field_name("left")?;
        let rhs = inner.child_by_field_name("right")?;
        // Only simple-identifier lhs for this pass; tuple/list/attribute/
        // subscript targets are deferred (rarer at module scope).
        if lhs.kind() != "identifier" {
            continue;
        }
        let name = node_text(lhs, source);
        let expr_ir = py_node_to_ir(&rhs, source);
        decls.push(serde_json::json!({ "bind": name, "expr": expr_ir }));
    }
    if decls.is_empty() {
        None
    } else {
        Some(serde_json::Value::Array(decls).to_string())
    }
}

fn extract_python_function_cfg(
    func_node: &Node,
    source: &str,
    file_path: &str,
    name: &str,
    module_preamble: Option<&str>,
) -> Result<ControlFlowGraph> {
    let mut cfg = ControlFlowGraph::new(
        name.to_string(),
        "python".to_string(),
        file_path.to_string(),
    );

    // Extract function signature.
    cfg.signature.is_async = func_node.kind() == "function_definition"
        && func_node
            .parent()
            .is_some_and(|p| node_text(p, source).starts_with("async"))
        || node_text(*func_node, source).starts_with("async");

    // Extract parameters.
    if let Some(params_node) = func_node.child_by_field_name("parameters") {
        for i in 0..params_node.child_count() {
            if let Some(param) = params_node.child(i) {
                let kind = param.kind();
                if kind == "identifier"
                    || kind == "typed_parameter"
                    || kind == "default_parameter"
                    || kind == "typed_default_parameter"
                    || kind == "list_splat_pattern"
                    || kind == "dictionary_splat_pattern"
                {
                    let param_name = if kind == "typed_parameter"
                        || kind == "default_parameter"
                        || kind == "typed_default_parameter"
                    {
                        param
                            .child_by_field_name("name")
                            .or_else(|| param.child(0))
                            .map(|n| node_text(n, source))
                            .unwrap_or_default()
                    } else {
                        node_text(param, source).trim_start_matches('*').to_string()
                    };

                    if param_name == "self" || param_name == "cls" {
                        cfg.signature.receiver_type = Some(param_name.clone());
                        continue;
                    }

                    let type_ann = if kind == "typed_parameter" || kind == "typed_default_parameter"
                    {
                        param
                            .child_by_field_name("type")
                            .map(|n| node_text(n, source))
                    } else {
                        None
                    };

                    let default_val =
                        if kind == "default_parameter" || kind == "typed_default_parameter" {
                            param
                                .child_by_field_name("value")
                                .map(|n| node_text(n, source))
                        } else {
                            None
                        };

                    let is_variadic = kind == "list_splat_pattern"
                        || kind == "dictionary_splat_pattern"
                        || node_text(param, source).starts_with('*');

                    cfg.signature.params.push(FunctionParam {
                        name: param_name,
                        type_annotation: type_ann,
                        default_value: default_val,
                        is_variadic,
                        semantic_type: Default::default(),
                    });
                }
            }
        }
    }

    // Extract return type annotation.
    if let Some(return_type) = func_node.child_by_field_name("return_type") {
        cfg.signature.return_type = Some(node_text(return_type, source));
    }

    // Extract callees from function body.
    if let Some(body) = func_node.child_by_field_name("body") {
        extract_callees(&body, source, &mut cfg.signature.callees);
    }

    let mut entry_props = ir_build_entry_props(&cfg.signature.params);
    if let Some(preamble_json) = module_preamble {
        entry_props.insert("module_preamble".to_string(), preamble_json.to_string());
    }
    let entry = cfg.add_node_with_props(
        CfgNodeKind::Entry {
            name: name.to_string(),
        },
        SourceSpan::from_tree_sitter(file_path, func_node),
        format!("def {name}"),
        entry_props,
    );
    cfg.entry = entry;

    let body = func_node.child_by_field_name("body").unwrap_or(*func_node);

    let last = extract_python_body(&body, source, file_path, &mut cfg, entry)?;

    if let Some(last_id) = last {
        if !matches!(cfg.nodes[last_id].kind, CfgNodeKind::Return) {
            let ret = cfg.add_node(
                CfgNodeKind::Return,
                SourceSpan::from_tree_sitter(file_path, &body),
                "implicit return".to_string(),
            );
            cfg.add_edge(last_id, ret, None);
            cfg.exits.push(ret);
        }
    } else {
        let ret = cfg.add_node(
            CfgNodeKind::Return,
            SourceSpan::from_tree_sitter(file_path, &body),
            "implicit return".to_string(),
        );
        cfg.add_edge(entry, ret, None);
        cfg.exits.push(ret);
    }

    Ok(cfg)
}

fn extract_python_body(
    body: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    predecessor: usize,
) -> Result<Option<usize>> {
    let mut current = predecessor;

    for i in 0..body.child_count() {
        let child = match body.child(i) {
            Some(c) => c,
            None => continue,
        };

        match child.kind() {
            "if_statement" => {
                let has_else = has_child_of_kind(&child, "else_clause");
                let branch = cfg.add_node(
                    CfgNodeKind::Branch {
                        exhaustive: has_else,
                    },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, branch, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "if merge".to_string(),
                );

                // Then body.
                if let Some(consequence) = child.child_by_field_name("consequence") {
                    let then_end =
                        extract_python_body(&consequence, source, file_path, cfg, branch)?;
                    if let Some(te) = then_end {
                        cfg.add_edge(te, merge, None);
                    }
                }

                // Elif / else branches.
                let mut found_else = false;
                for j in 0..child.child_count() {
                    if let Some(clause) = child.child(j) {
                        match clause.kind() {
                            "elif_clause" => {
                                if let Some(elif_body) = clause.child_by_field_name("consequence") {
                                    let elif_end = extract_python_body(
                                        &elif_body, source, file_path, cfg, branch,
                                    )?;
                                    if let Some(ee) = elif_end {
                                        cfg.add_edge(ee, merge, None);
                                    }
                                }
                            }
                            "else_clause" => {
                                found_else = true;
                                if let Some(else_body) = clause.child_by_field_name("body") {
                                    let else_end = extract_python_body(
                                        &else_body, source, file_path, cfg, branch,
                                    )?;
                                    if let Some(ee) = else_end {
                                        cfg.add_edge(ee, merge, None);
                                    }
                                }
                            }
                            _ => {}
                        }
                    }
                }

                if !found_else {
                    cfg.add_edge(branch, merge, Some("no-else".into()));
                }

                current = merge;
            }

            "for_statement" => {
                let loop_node = cfg.add_node(
                    CfgNodeKind::Loop { bounded: true },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, loop_node, None);

                if let Some(loop_body) = child.child_by_field_name("body") {
                    let body_end =
                        extract_python_body(&loop_body, source, file_path, cfg, loop_node)?;
                    if let Some(be) = body_end {
                        cfg.add_edge(be, loop_node, Some("back".into()));
                    }
                }

                let exit = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "for exit".to_string(),
                );
                cfg.add_edge(loop_node, exit, Some("exit".into()));
                current = exit;
            }

            "while_statement" => {
                let text = node_text(child, source);
                // while loops with explicit termination conditions are bounded.
                let bounded = text.contains(" < ")
                    || text.contains(" <= ")
                    || text.contains(" > ")
                    || text.contains(" >= ")
                    || text.contains(" not ")
                    || text.contains("len(")
                    || text.contains(".empty")
                    || text.contains("is not None");
                let loop_node = cfg.add_node(
                    CfgNodeKind::Loop { bounded },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, loop_node, None);

                if let Some(loop_body) = child.child_by_field_name("body") {
                    let body_end =
                        extract_python_body(&loop_body, source, file_path, cfg, loop_node)?;
                    if let Some(be) = body_end {
                        cfg.add_edge(be, loop_node, Some("back".into()));
                    }
                }

                let exit = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "while exit".to_string(),
                );
                cfg.add_edge(loop_node, exit, Some("exit".into()));
                current = exit;
            }

            "try_statement" => {
                let try_entry = cfg.add_node(
                    CfgNodeKind::TryEntry,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "try".to_string(),
                );
                cfg.add_edge(current, try_entry, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "try merge".to_string(),
                );

                // Try body.
                if let Some(try_body) = child.child_by_field_name("body") {
                    let try_end =
                        extract_python_body(&try_body, source, file_path, cfg, try_entry)?;
                    if let Some(te) = try_end {
                        cfg.add_edge(te, merge, None);
                    }
                }

                // Except handlers.
                let mut after_try = merge;
                for j in 0..child.child_count() {
                    if let Some(handler) = child.child(j) {
                        if handler.kind() == "except_clause" {
                            let catch_node = cfg.add_node(
                                CfgNodeKind::CatchHandler,
                                SourceSpan::from_tree_sitter(file_path, &handler),
                                "except".to_string(),
                            );
                            cfg.add_exceptional_edge(try_entry, catch_node, Some("error".into()));

                            // Except body is direct children.
                            let catch_end =
                                extract_python_body(&handler, source, file_path, cfg, catch_node)?;
                            if let Some(ce) = catch_end {
                                cfg.add_edge(ce, merge, None);
                            }
                        } else if handler.kind() == "finally_clause" {
                            let finally_node = cfg.add_node(
                                CfgNodeKind::FinallyHandler,
                                SourceSpan::from_tree_sitter(file_path, &handler),
                                "finally".to_string(),
                            );
                            cfg.add_edge(merge, finally_node, None);

                            let finally_end = extract_python_body(
                                &handler,
                                source,
                                file_path,
                                cfg,
                                finally_node,
                            )?;
                            after_try = finally_end.unwrap_or(finally_node);
                        }
                    }
                }

                current = after_try;
            }

            "with_statement" => {
                // with statement = acquire + body + implicit release.
                let acquire = cfg.add_node(
                    CfgNodeKind::ResourceAcquire {
                        resource_kind: ResourceKind::Generic("context_manager".to_string()),
                    },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, acquire, None);

                if let Some(with_body) = child.child_by_field_name("body") {
                    let body_end =
                        extract_python_body(&with_body, source, file_path, cfg, acquire)?;
                    if let Some(be) = body_end {
                        let release = cfg.add_node(
                            CfgNodeKind::ResourceRelease {
                                resource_kind: ResourceKind::Generic("context_manager".to_string()),
                            },
                            SourceSpan::from_tree_sitter(file_path, &child),
                            "with exit".to_string(),
                        );
                        cfg.add_edge(be, release, None);
                        current = release;
                    }
                }
            }

            "return_statement" => {
                let extra = build_return_props(&child, source);
                let ret = cfg.add_node_with_props(
                    CfgNodeKind::Return,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, ret, None);
                cfg.exits.push(ret);
                return Ok(Some(ret));
            }

            "raise_statement" => {
                let stmt = cfg.add_node(
                    CfgNodeKind::Return,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                );
                cfg.add_edge(current, stmt, None);
                cfg.exits.push(stmt);
                return Ok(Some(stmt));
            }

            "expression_statement" => {
                let node_kind = classify_python_expression(&child, source);
                let extra = build_expression_statement_props(&child, source);
                let stmt = cfg.add_node_with_props(
                    node_kind,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }

            "comment" | "decorator" | "pass_statement" => {}

            _ => {
                let stmt = cfg.add_node(
                    CfgNodeKind::Statement,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }
        }
    }

    Ok(Some(current))
}

fn classify_python_expression(node: &Node, source: &str) -> CfgNodeKind {
    let text = node_text(*node, source);

    // Resource acquire patterns.
    if text.contains("open(") {
        return CfgNodeKind::ResourceAcquire {
            resource_kind: ResourceKind::File,
        };
    }
    if text.contains("connect(") || text.contains("create_connection(") {
        return CfgNodeKind::ResourceAcquire {
            resource_kind: ResourceKind::Connection,
        };
    }

    // Resource release patterns.
    if text.contains(".close()") {
        return CfgNodeKind::ResourceRelease {
            resource_kind: ResourceKind::Generic("resource".to_string()),
        };
    }

    // Async patterns.
    if text.starts_with("await ") || text.contains("await ") {
        return CfgNodeKind::SyncJoin;
    }

    // Thread spawn.
    if text.contains("Thread(") || text.contains("Process(") || text.contains("create_task(") {
        return CfgNodeKind::ConcurrentSpawn;
    }

    // Lock acquire.
    if text.contains(".acquire(") || text.contains("Lock(") {
        return CfgNodeKind::LockAcquire { lock_id: None };
    }

    // Lock release.
    if text.contains(".release(") {
        return CfgNodeKind::LockRelease { lock_id: None };
    }

    CfgNodeKind::Statement
}

fn has_child_of_kind(node: &Node, kind: &str) -> bool {
    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            if child.kind() == kind {
                return true;
            }
        }
    }
    false
}

fn node_text(node: Node, source: &str) -> String {
    source[node.start_byte()..node.end_byte()].to_string()
}

fn node_text_truncated(node: &Node, source: &str, max: usize) -> String {
    let full = &source[node.start_byte()..node.end_byte()];
    let first_line = full.lines().next().unwrap_or(full);
    if first_line.len() > max {
        let end = first_line
            .char_indices()
            .nth(max)
            .map(|(i, _)| i)
            .unwrap_or(first_line.len());
        format!("{}...", &first_line[..end])
    } else {
        first_line.to_string()
    }
}

/// Extract function call targets from a tree-sitter subtree.
fn extract_callees(node: &Node, source: &str, callees: &mut Vec<String>) {
    if node.kind() == "call" {
        if let Some(func) = node.child_by_field_name("function") {
            let callee_text = node_text(func, source);
            // Skip self.method() → just capture "method", also skip builtins.
            let callee = callee_text
                .strip_prefix("self.")
                .unwrap_or(&callee_text)
                .to_string();
            if !callee.is_empty() && !callees.contains(&callee) {
                callees.push(callee);
            }
        }
    }

    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            // Don't recurse into nested function definitions.
            if child.kind() != "function_definition" && child.kind() != "class_definition" {
                extract_callees(&child, source, callees);
            }
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Semantic expression IR for orchestration mode.
//
// Mirrors the TypeScript extractor's IR: walks tree-sitter-python expression
// nodes and emits a small JSON IR shape that downstream walkers (notably
// gnexec) can evaluate without re-parsing source. Anything not recognized
// falls back to `{ "kind": "raw", "text": <source> }` so the GG remains
// round-trippable.
// ─────────────────────────────────────────────────────────────────────────────

/// Build orchestration-only properties for a `return_statement` node.
///
/// Python additionally surfaces `callee`/`args` for `return foo(...)` shape on
/// top of the narrow shared `expr`-only contract. We layer that on locally so
/// the shared `ir_build_return_props` stays language-agnostic.
fn build_return_props(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let expr = node
        .named_children(&mut cursor)
        .find(|child| !is_py_skip(child));
    let Some(expr_node) = expr else {
        return BTreeMap::new();
    };
    let ir = py_node_to_ir(&expr_node, source);

    let mut props = ir_build_return_props(ir.clone());
    if let Some((callee, args)) = ir_call_callee_args(&ir) {
        props.insert("callee".to_string(), callee);
        if let Ok(args_json) = serde_json::to_string(&args) {
            props.insert("args".to_string(), args_json);
        }
    }
    props
}

/// Build orchestration-only properties for an `expression_statement` node.
/// In Python the inner is `assignment`, `call`, etc. Assignment dispatches to
/// the shared declaration-props helper when the LHS is a simple identifier;
/// pattern / target shapes are handled inline (Python-specific lvalue kinds).
fn build_expression_statement_props(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let inner = node
        .named_children(&mut cursor)
        .find(|child| !is_py_skip(child));
    let Some(inner) = inner else {
        return BTreeMap::new();
    };

    if inner.kind() == "assignment" {
        let left = inner.child_by_field_name("left");
        let right = inner.child_by_field_name("right");
        let bind_ir = left.map(|n| py_node_to_ir(&n, source));
        let value_ir = right.map(|n| py_node_to_ir(&n, source));

        // Simple `x = expr` → reuse the shared declaration helper.
        if let (Some(b_ir), Some(v_ir)) = (bind_ir.as_ref(), value_ir.clone()) {
            if let Some(simple) = ir_as_simple_ident(b_ir) {
                return ir_build_declaration_props(&simple, v_ir);
            }
        }

        // Python-specific lvalue shapes (tuple unpacking, attribute / subscript
        // targets) — handle inline so we don't widen the shared contract.
        let mut props = BTreeMap::new();
        if let (Some(left_node), Some(b_ir)) = (left, bind_ir) {
            if let Some(name) = ir_as_simple_ident(&b_ir) {
                props.insert("bind".to_string(), name);
            } else if matches!(left_node.kind(), "pattern_list" | "tuple_pattern") {
                if let Ok(s) = serde_json::to_string(&b_ir) {
                    props.insert("bind_pattern".to_string(), s);
                }
            } else if let Ok(s) = serde_json::to_string(&b_ir) {
                props.insert("bind_target".to_string(), s);
            }
        }
        if let Some(v_ir) = value_ir {
            if let Ok(s) = serde_json::to_string(&v_ir) {
                props.insert("expr".to_string(), s);
            }
            if let Some((callee, args)) = ir_call_callee_args(&v_ir) {
                props.insert("callee".to_string(), callee);
                if let Ok(args_json) = serde_json::to_string(&args) {
                    props.insert("args".to_string(), args_json);
                }
            }
        }
        return props;
    }

    // Bare expression statement (e.g. a function call as a statement).
    let ir = py_node_to_ir(&inner, source);
    ir_build_expression_statement_props(ir, None, None)
}

/// Convert a tree-sitter-python expression node into the orchestration IR.
fn py_node_to_ir(node: &Node, source: &str) -> serde_json::Value {
    use serde_json::{json, Number, Value};
    let kind = node.kind();
    match kind {
        "integer" => {
            let text = node_text(*node, source);
            let cleaned = text.replace('_', "");
            let value = if let Ok(i) = cleaned.parse::<i64>() {
                Value::Number(Number::from(i))
            } else if let Some(stripped) = cleaned
                .strip_prefix("0x")
                .or_else(|| cleaned.strip_prefix("0X"))
            {
                i64::from_str_radix(stripped, 16)
                    .ok()
                    .map(|n| Value::Number(Number::from(n)))
                    .unwrap_or(Value::String(text.clone()))
            } else if let Some(stripped) = cleaned
                .strip_prefix("0o")
                .or_else(|| cleaned.strip_prefix("0O"))
            {
                i64::from_str_radix(stripped, 8)
                    .ok()
                    .map(|n| Value::Number(Number::from(n)))
                    .unwrap_or(Value::String(text.clone()))
            } else if let Some(stripped) = cleaned
                .strip_prefix("0b")
                .or_else(|| cleaned.strip_prefix("0B"))
            {
                i64::from_str_radix(stripped, 2)
                    .ok()
                    .map(|n| Value::Number(Number::from(n)))
                    .unwrap_or(Value::String(text.clone()))
            } else {
                Value::String(text.clone())
            };
            json!({ "kind": "literal", "value": value })
        }
        "float" => {
            let text = node_text(*node, source);
            let cleaned = text.replace('_', "");
            let value = cleaned
                .parse::<f64>()
                .ok()
                .and_then(Number::from_f64)
                .map(Value::Number)
                .unwrap_or(Value::String(text));
            json!({ "kind": "literal", "value": value })
        }
        "true" => json!({ "kind": "literal", "value": true }),
        "false" => json!({ "kind": "literal", "value": false }),
        "none" => json!({ "kind": "literal", "value": Value::Null }),
        "string" => py_string_to_ir(node, source),
        "concatenated_string" => {
            let mut parts: Vec<Value> = Vec::new();
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if child.kind() == "string" {
                    let inner = py_string_to_ir(&child, source);
                    if inner.get("kind").and_then(|k| k.as_str()) == Some("template") {
                        if let Some(arr) = inner.get("parts").and_then(|p| p.as_array()) {
                            for p in arr {
                                parts.push(p.clone());
                            }
                        }
                    } else if inner.get("kind").and_then(|k| k.as_str()) == Some("literal") {
                        if let Some(s) = inner.get("value").and_then(|v| v.as_str()) {
                            parts.push(json!({ "kind": "text", "s": s }));
                        }
                    }
                }
            }
            let all_text = parts
                .iter()
                .all(|p| p.get("kind").and_then(|k| k.as_str()) == Some("text"));
            if all_text {
                let joined: String = parts
                    .iter()
                    .filter_map(|p| p.get("s").and_then(|s| s.as_str()))
                    .collect();
                json!({ "kind": "literal", "value": joined })
            } else {
                json!({ "kind": "template", "parts": parts })
            }
        }
        "identifier" => json!({ "kind": "ident", "name": node_text(*node, source) }),
        "parenthesized_expression" => {
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if !is_py_skip(&child) {
                    return py_node_to_ir(&child, source);
                }
            }
            json!({ "kind": "raw", "text": node_text(*node, source) })
        }
        "attribute" => {
            let obj = node
                .child_by_field_name("object")
                .map(|n| py_node_to_ir(&n, source))
                .unwrap_or(serde_json::Value::Null);
            let prop = node
                .child_by_field_name("attribute")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "member", "obj": obj, "prop": prop })
        }
        "subscript" => {
            // Simple `x[k]`. Slices fall back to `raw`.
            let value_node = node.child_by_field_name("value");
            let sub_node = node.child_by_field_name("subscript");
            match (value_node, sub_node) {
                (Some(v), Some(k)) => {
                    let obj = py_node_to_ir(&v, source);
                    if k.kind() == "slice" {
                        // Python slice: x[start:stop:step]. In tree-sitter-python,
                        // these aren't named fields; we find them by position
                        // relative to the colons.
                        let mut start_node = None;
                        let mut stop_node = None;
                        let mut step_node = None;
                        let mut colon_count = 0;

                        for i in 0..k.child_count() {
                            let child = k.child(i).unwrap();
                            if child.kind() == ":" {
                                colon_count += 1;
                                continue;
                            }
                            if child.is_named() {
                                if colon_count == 0 {
                                    start_node = Some(child);
                                } else if colon_count == 1 {
                                    stop_node = Some(child);
                                } else {
                                    step_node = Some(child);
                                }
                            }
                        }

                        let mut m = serde_json::Map::new();
                        m.insert("kind".into(), serde_json::Value::String("slice".into()));
                        if let Some(n) = start_node {
                            m.insert("start".into(), py_node_to_ir(&n, source));
                        }
                        if let Some(n) = stop_node {
                            m.insert("stop".into(), py_node_to_ir(&n, source));
                        }
                        if let Some(n) = step_node {
                            m.insert("step".into(), py_node_to_ir(&n, source));
                        }
                        json!({ "kind": "index", "obj": obj, "key": serde_json::Value::Object(m) })
                    } else {
                        let key = py_node_to_ir(&k, source);
                        json!({ "kind": "index", "obj": obj, "key": key })
                    }
                }
                _ => json!({ "kind": "raw", "text": node_text(*node, source) }),
            }
        }
        "call" => {
            let func = node.child_by_field_name("function");
            let callee_value = match &func {
                Some(f) if f.kind() == "identifier" => {
                    serde_json::Value::String(node_text(*f, source))
                }
                Some(f) => py_node_to_ir(f, source),
                None => serde_json::Value::Null,
            };
            let mut args: Vec<serde_json::Value> = Vec::new();
            if let Some(args_node) = node.child_by_field_name("arguments") {
                let mut cursor = args_node.walk();
                for child in args_node.named_children(&mut cursor) {
                    if is_py_skip(&child) {
                        continue;
                    }
                    match child.kind() {
                        "keyword_argument" => {
                            let name = child
                                .child_by_field_name("name")
                                .map(|n| node_text(n, source))
                                .unwrap_or_default();
                            let value = child
                                .child_by_field_name("value")
                                .map(|n| py_node_to_ir(&n, source))
                                .unwrap_or(serde_json::Value::Null);
                            args.push(json!({ "kind": "kwarg", "name": name, "value": value }));
                        }
                        "list_splat" | "dictionary_splat" => {
                            let mut inner_cursor = child.walk();
                            let mut inner_node = None;
                            for c in child.named_children(&mut inner_cursor) {
                                if !is_py_skip(&c) {
                                    inner_node = Some(c);
                                    break;
                                }
                            }
                            let inner_ir = inner_node
                                .map(|n| py_node_to_ir(&n, source))
                                .unwrap_or(serde_json::Value::Null);
                            args.push(json!({ "kind": "spread", "arg": inner_ir }));
                        }
                        _ => args.push(py_node_to_ir(&child, source)),
                    }
                }
            }
            json!({ "kind": "call", "callee": callee_value, "args": args })
        }
        "binary_operator" => {
            let lhs = node
                .child_by_field_name("left")
                .map(|n| py_node_to_ir(&n, source))
                .unwrap_or(serde_json::Value::Null);
            let rhs = node
                .child_by_field_name("right")
                .map(|n| py_node_to_ir(&n, source))
                .unwrap_or(serde_json::Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "binary", "op": op, "lhs": lhs, "rhs": rhs })
        }
        "comparison_operator" => {
            // Simple binary form: 3 children = `lhs op rhs`. Chained comparisons
            // (`a < b < c`) fall back to raw.
            if node.child_count() == 3 {
                let lhs_node = node.child(0);
                let op_node = node.child(1);
                let rhs_node = node.child(2);
                if let (Some(l), Some(o), Some(r)) = (lhs_node, op_node, rhs_node) {
                    let lhs = py_node_to_ir(&l, source);
                    let rhs = py_node_to_ir(&r, source);
                    let op = node_text(o, source);
                    return json!({ "kind": "binary", "op": op, "lhs": lhs, "rhs": rhs });
                }
            }
            json!({ "kind": "raw", "text": node_text(*node, source) })
        }
        "boolean_operator" => {
            let lhs = node
                .child_by_field_name("left")
                .map(|n| py_node_to_ir(&n, source))
                .unwrap_or(serde_json::Value::Null);
            let rhs = node
                .child_by_field_name("right")
                .map(|n| py_node_to_ir(&n, source))
                .unwrap_or(serde_json::Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "binary", "op": op, "lhs": lhs, "rhs": rhs })
        }
        "unary_operator" => {
            let arg = node
                .child_by_field_name("argument")
                .map(|n| py_node_to_ir(&n, source))
                .unwrap_or(serde_json::Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "unary", "op": op, "arg": arg })
        }
        "not_operator" => {
            let arg = node
                .child_by_field_name("argument")
                .map(|n| py_node_to_ir(&n, source))
                .unwrap_or(serde_json::Value::Null);
            json!({ "kind": "unary", "op": "not", "arg": arg })
        }
        "conditional_expression" => {
            // Python: `consequence if condition else alternative` — children are
            // positional. Walk named children, expect [cons, cond, alt].
            let mut cursor = node.walk();
            let named: Vec<Node> = node
                .named_children(&mut cursor)
                .filter(|c| !is_py_skip(c))
                .collect();
            if named.len() == 3 {
                let cons = py_node_to_ir(&named[0], source);
                let cond = py_node_to_ir(&named[1], source);
                let alt = py_node_to_ir(&named[2], source);
                return json!({ "kind": "ternary", "cond": cond, "cons": cons, "alt": alt });
            }
            json!({ "kind": "raw", "text": node_text(*node, source) })
        }
        "list" => {
            let mut items: Vec<serde_json::Value> = Vec::new();
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if is_py_skip(&child) {
                    continue;
                }
                if child.kind() == "list_splat" {
                    let mut inner_cursor = child.walk();
                    let mut inner_node = None;
                    for c in child.named_children(&mut inner_cursor) {
                        if !is_py_skip(&c) {
                            inner_node = Some(c);
                            break;
                        }
                    }
                    let inner_ir = inner_node
                        .map(|n| py_node_to_ir(&n, source))
                        .unwrap_or(serde_json::Value::Null);
                    items.push(json!({ "kind": "spread", "arg": inner_ir }));
                } else {
                    items.push(py_node_to_ir(&child, source));
                }
            }
            json!({ "kind": "array", "items": items })
        }
        "tuple" => {
            // Treat tuple as array IR — same shape; consumers can disambiguate
            // via byte-range fallback if exact tuple-vs-list semantics matter.
            let mut items: Vec<serde_json::Value> = Vec::new();
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if is_py_skip(&child) {
                    continue;
                }
                items.push(py_node_to_ir(&child, source));
            }
            json!({ "kind": "array", "items": items })
        }
        "dictionary" => {
            // Only string-keyed pairs map cleanly to the canonical IR. Anything
            // else (computed keys, dict comprehensions, splats) → raw fallback.
            let mut fields: Vec<serde_json::Value> = Vec::new();
            let mut all_string_keys = true;
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if is_py_skip(&child) {
                    continue;
                }
                if child.kind() == "pair" {
                    let key_node = child.child_by_field_name("key");
                    let value_node = child.child_by_field_name("value");
                    if let (Some(k), Some(v)) = (key_node, value_node) {
                        if k.kind() == "string" {
                            let key_str = py_string_literal_value(&k, source);
                            let value_ir = py_node_to_ir(&v, source);
                            fields.push(json!({ "k": key_str, "v": value_ir }));
                            continue;
                        }
                    }
                    all_string_keys = false;
                    break;
                } else if child.kind() == "dictionary_splat" {
                    all_string_keys = false;
                    break;
                }
            }
            if all_string_keys {
                json!({ "kind": "object", "fields": fields })
            } else {
                json!({ "kind": "raw", "text": node_text(*node, source) })
            }
        }
        "await" => {
            let mut cursor = node.walk();
            let mut inner_node = None;
            for c in node.named_children(&mut cursor) {
                if !is_py_skip(&c) {
                    inner_node = Some(c);
                    break;
                }
            }
            let inner_ir = inner_node
                .map(|n| py_node_to_ir(&n, source))
                .unwrap_or(serde_json::Value::Null);
            json!({ "kind": "await", "arg": inner_ir })
        }
        "yield" => {
            let mut cursor = node.walk();
            let mut inner_node = None;
            for c in node.named_children(&mut cursor) {
                if !is_py_skip(&c) {
                    inner_node = Some(c);
                    break;
                }
            }
            let inner_ir = inner_node
                .map(|n| py_node_to_ir(&n, source))
                .unwrap_or(serde_json::Value::Null);
            json!({ "kind": "yield", "arg": inner_ir })
        }
        "ellipsis" => json!({ "kind": "literal", "value": "..." }),
        // Anything else: emit a raw escape hatch so the GG remains complete.
        _ => json!({ "kind": "raw", "text": node_text(*node, source) }),
    }
}

/// Convert a `string` node to an IR value. Plain strings → `literal`,
/// f-strings (with interpolations) → `template`. Bytes/raw strings fall
/// through to literal too — the host runtime can disambiguate via byte range.
fn py_string_to_ir(node: &Node, source: &str) -> serde_json::Value {
    use serde_json::{json, Value};
    // Detect f-string by looking at start prefix.
    let mut is_f = false;
    let mut cursor = node.walk();
    for child in node.children(&mut cursor) {
        if child.kind() == "string_start" {
            let txt = node_text(child, source);
            let lower = txt.to_lowercase();
            // Python prefixes can combine: rb, fr, etc. Detect 'f' anywhere
            // before the opening quote.
            let before_quote: String = lower
                .chars()
                .take_while(|c| *c != '"' && *c != '\'')
                .collect();
            if before_quote.contains('f') {
                is_f = true;
            }
            break;
        }
    }

    if !is_f {
        let s = py_string_literal_value(node, source);
        return json!({ "kind": "literal", "value": s });
    }

    // f-string: walk children, emit template parts.
    let mut parts: Vec<Value> = Vec::new();
    let mut cursor = node.walk();
    for child in node.children(&mut cursor) {
        match child.kind() {
            "string_content" | "escape_sequence" => {
                parts.push(json!({ "kind": "text", "s": node_text(child, source) }));
            }
            "interpolation" => {
                let mut expr_node = child.child_by_field_name("expression");
                if expr_node.is_none() {
                    let mut sub = child.walk();
                    for c in child.named_children(&mut sub) {
                        if !is_py_skip(&c) {
                            expr_node = Some(c);
                            break;
                        }
                    }
                }
                let inner_ir = expr_node
                    .map(|n| py_node_to_ir(&n, source))
                    .unwrap_or(Value::Null);
                parts.push(json!({ "kind": "expr", "e": inner_ir }));
            }
            _ => {}
        }
    }
    json!({ "kind": "template", "parts": parts })
}

/// Strip prefix/quotes from a Python `string` node, concatenating fragments.
fn py_string_literal_value(node: &Node, source: &str) -> String {
    let mut out = String::new();
    let mut cursor = node.walk();
    for child in node.children(&mut cursor) {
        if child.kind() == "string_content" || child.kind() == "escape_sequence" {
            out.push_str(&node_text(child, source));
        }
    }
    if !out.is_empty() {
        return out;
    }
    // Fallback: strip prefix letters and outer quotes from the raw text.
    let raw = node_text(*node, source);
    let trimmed = raw.trim();
    let after_prefix: &str = {
        let mut idx = 0;
        for (i, ch) in trimmed.char_indices() {
            if matches!(ch, 'r' | 'R' | 'b' | 'B' | 'u' | 'U' | 'f' | 'F') {
                idx = i + ch.len_utf8();
            } else {
                break;
            }
        }
        &trimmed[idx..]
    };
    if after_prefix.len() >= 6
        && (after_prefix.starts_with("\"\"\"") || after_prefix.starts_with("'''"))
        && (after_prefix.ends_with("\"\"\"") || after_prefix.ends_with("'''"))
    {
        return after_prefix[3..after_prefix.len() - 3].to_string();
    }
    if after_prefix.len() >= 2 {
        let bytes = after_prefix.as_bytes();
        let q = bytes[0];
        if (q == b'"' || q == b'\'') && bytes[bytes.len() - 1] == q {
            return after_prefix[1..after_prefix.len() - 1].to_string();
        }
    }
    raw
}

/// True if `node` is a comment we want to skip while walking expressions.
fn is_py_skip(node: &Node) -> bool {
    matches!(node.kind(), "comment")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn extracts_python_function() {
        let source = r#"
def process_data(data):
    if not data:
        raise ValueError("empty")
    with open("output.txt", "w") as f:
        f.write(str(data))
    return True
"#;

        let extractor = PythonExtractor;
        let cfgs = extractor.extract(source, "test.py").unwrap();
        assert_eq!(cfgs.len(), 1);
        assert_eq!(cfgs[0].function_name, "process_data");
    }

    #[test]
    fn with_statement_has_acquire_release() {
        let source = r#"
def safe_read():
    with open("data.txt") as f:
        return f.read()
"#;

        let extractor = PythonExtractor;
        let cfgs = extractor.extract(source, "test.py").unwrap();
        let has_acquire = cfgs[0]
            .nodes
            .iter()
            .any(|n| matches!(n.kind, CfgNodeKind::ResourceAcquire { .. }));
        let has_release = cfgs[0]
            .nodes
            .iter()
            .any(|n| matches!(n.kind, CfgNodeKind::ResourceRelease { .. }));
        assert!(has_acquire, "with should create acquire");
        assert!(has_release, "with should create release");
    }
}
